import React, {type PropsWithChildren} from "react";
import {useLanguage} from "../../hooks";
import type {ITranslateComponent} from "@lmb-it/kitsconcerto-types";

const Translate = ({label, children}: PropsWithChildren<ITranslateComponent>) => {
    const {t} = useLanguage();


    return (
        <>
            {label
                ? t(label)
                : typeof children == "string"
                    ? t(children)
                    : children}
        </>
    );
}
export default Translate;
